using namespace std;
#define ll long long
#define M 1000000007
#define N 200000
#define K 1000000
#define inf 0x3f3f3f3f
int main()
{
    ll k;
    cin>>k;
    if(k==1){
        cout<<4<<endl;
    }else{
        ll ans=1;
        ll sum=0;
        while(sum<k){
            ans++;
            sum+=ans/10+ans%10;
        }
        if(sum==k){
            cout<<ans<<endl;
        }else{
            cout<<-1<<endl;
        }
    }
    return 0;
}
